// ── Helper functions ────────────────────────────────────────

/** Returns the local path for an item sprite, or null if not available */
export function getItemSprite(slug: string): string | null {
  return ITEM_SPRITES[slug] ?? null
}

/** Returns the local path for a type icon, or null if not available */
export function getTypeIcon(typeName: string): string | null {
  return TYPE_SPRITES[typeName] ?? null
}

/** Returns local shiny sprite paths for a Pokémon, or null */
export function getShinySpriteSet(
  pokemonId: number
): ShinySpriteEntry | null {
  return SHINY_SPRITES[pokemonId] ?? null
}

/** Resolve item name to sprite slug.
 *  Handles common variations: spaces→dashes, accents stripped, lowercase.
 *  e.g. "Focus Band" → "focus-band", "Poké Ball" → "poke-ball"
 */
export function resolveItemSlug(itemName: string): string {
  return itemName
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")  // strip accents
    .replace(/[^a-z0-9]+/g, "-")         // spaces/symbols → dashes
    .replace(/^-|-$/g, "")               // trim leading/trailing dashes
}

/** Get item sprite by display name (case-insensitive, accent-insensitive).
 *  e.g. getItemSpriteByName("Focus Band") → "sprites/items/focus-band.png"
 */
export function getItemSpriteByName(itemName: string): string | null {
  const slug = resolveItemSlug(itemName)
  return ITEM_SPRITES[slug] ?? null
}
